function Invoke-NetIPGraphRequest {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][ValidateSet('GET','POST','PATCH','DELETE')][string] $Method,
        [Parameter(Mandatory)][string] $Uri,
        [AllowNull()] $Body = $null,
        [switch] $SuppressNotFoundLog
    )

    if ($sync.App.Mock) {
        throw 'Mock mode should not call Microsoft Graph.'
    }
    $params = @{
        Method      = $Method
        Uri         = $Uri
        ErrorAction = 'Stop'
    }
    if ($null -ne $Body) {
        $params.Body = if ($Body -is [string]) { $Body } else { ($Body | ConvertTo-Json -Depth 30) }
        $params.ContentType = 'application/json'
    }
    try {
        return Invoke-MgGraphRequest @params
    }
    catch {
        $message = [string]$_
        $isNotFound = $message -match '404|Request_ResourceNotFound|Resource .* does not exist'
        if (-not ($SuppressNotFoundLog -and $isNotFound)) {
            Write-NetIPLog -Level ERROR -Message (ConvertTo-NetIPRedactedError -ErrorRecord $_)
        }
        throw
    }
}

function Invoke-NetIPRunspace {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][scriptblock] $ScriptBlock,
        [object[]] $ArgumentList = @()
    )

    if ($sync.UI.ProcessRunning) {
        [System.Windows.MessageBox]::Show('Der kører allerede en opgave. Vent til den er færdig.', $sync.App.Name, 'OK', 'Information') | Out-Null
        return
    }
    $sync.UI.ProcessRunning = $true
    if ($sync.WPFProgressBar) {
        $sync.WPFProgressBar.Dispatcher.Invoke([System.Action]{ $sync.WPFProgressBar.IsIndeterminate = $true })
    }
    $ps = [PowerShell]::Create()
    $ps.RunspacePool = $sync.Runspace
    [void]$ps.AddScript({
        param($innerScript, $innerArgs)
        try {
            & $innerScript @innerArgs
        }
        catch {
            $friendly = 'Der opstod en fejl. Se logfilen for tekniske detaljer.'
            Write-NetIPLog -Level ERROR -Message (ConvertTo-NetIPRedactedError -ErrorRecord $_)
            $sync.State.Errors += $friendly
            if ($sync.Form) {
                $sync.Form.Dispatcher.Invoke([System.Action]{
                    $sync.WPFStatusText.Text = $friendly
                    [System.Windows.MessageBox]::Show($friendly, $sync.App.Name, 'OK', 'Error') | Out-Null
                })
            }
        }
        finally {
            $sync.UI.ProcessRunning = $false
            if ($sync.Form) {
                $sync.Form.Dispatcher.Invoke([System.Action]{
                    $sync.WPFProgressBar.IsIndeterminate = $false
                    Update-NetIPUIState
                })
            }
        }
    }).AddArgument($ScriptBlock).AddArgument($ArgumentList) | Out-Null
    [void]$ps.BeginInvoke()
}

function New-BreakGlassUser {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [Parameter(Mandatory)][string] $UserPrincipalName,
        [Parameter(Mandatory)][string] $Password
    )

    if ($sync.App.Mock) {
        return [pscustomobject]@{ id = "mock-$($UserPrincipalName.Split('@')[0])"; displayName = $DisplayName; userPrincipalName = $UserPrincipalName; accountEnabled = $true; EnsureStatus = 'Created' }
    }
    $mailNickname = ($UserPrincipalName.Split('@')[0] -replace '[^A-Za-z0-9]', '')
    $body = @{
        accountEnabled    = $true
        displayName       = $DisplayName
        mailNickname      = $mailNickname
        userPrincipalName = $UserPrincipalName
        passwordProfile   = @{
            forceChangePasswordNextSignIn = $false
            password = $Password
        }
    }
    Invoke-NetIPGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/users' -Body $body | Out-Null
    $user = Get-NetIPUserByUpn -UserPrincipalName $UserPrincipalName
    $user | Add-Member -MemberType NoteProperty -Name EnsureStatus -Value 'Created' -Force
    return $user
}

function New-NetIPHandoffHtml {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] $Result,
        [Parameter(Mandatory)][string] $OutputFolder
    )

    function ConvertTo-NetIPHtmlValue([AllowNull()]$value) { [System.Net.WebUtility]::HtmlEncode([string]$value) }
    function Get-NetIPTablePropertyNames([AllowNull()]$item) {
        if ($null -eq $item) { return @() }
        if ($item -is [System.Collections.IDictionary]) {
            return @($item.Keys | ForEach-Object { [string]$_ })
        }
        return @($item.PSObject.Properties.Name)
    }
    function Rows($items) {
        if (-not $items -or @($items).Count -eq 0) { return '<p>Ingen.</p>' }
        $props = @($items | ForEach-Object { Get-NetIPTablePropertyNames $_ } | Select-Object -Unique)
        $head = '<tr>' + (($props | ForEach-Object { '<th>{0}</th>' -f (ConvertTo-NetIPHtmlValue $_) }) -join '') + '</tr>'
        $body = foreach ($item in $items) {
            '<tr>' + (($props | ForEach-Object { '<td>{0}</td>' -f (ConvertTo-NetIPHtmlValue (Get-NetIPObjectPropertyValue -InputObject $item -Name $_)) }) -join '') + '</tr>'
        }
        return '<table>' + $head + ($body -join "`n") + '</table>'
    }

    $path = Join-Path $OutputFolder 'handoff.html'
    New-Item -ItemType Directory -Force -Path $OutputFolder | Out-Null
    $account1 = Get-NetIPObjectPropertyValue -InputObject $Result -Name 'Account1'
    $account2 = Get-NetIPObjectPropertyValue -InputObject $Result -Name 'Account2'
    $group = Get-NetIPObjectPropertyValue -InputObject $Result -Name 'Group'
    $changed = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'CAPoliciesChanged')
    $already = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'CAPoliciesAlreadyExcluded')
    $failed = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'CAPoliciesFailed')
    $memberships = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'GroupMembership')
    $roleAssignments = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'RoleAssignments')
    $resultWarnings = @(Get-NetIPObjectPropertyValue -InputObject $Result -Name 'Warnings')
    $changedTable = Rows $changed
    $alreadyTable = Rows $already
    $failedTable = Rows $failed
    $membershipTable = Rows $memberships
    $roleAssignmentTable = Rows $roleAssignments
    $warnings = if ($resultWarnings.Count -gt 0) { '<ul>' + (($resultWarnings | ForEach-Object { '<li>{0}</li>' -f (ConvertTo-NetIPHtmlValue $_) }) -join '') + '</ul>' } else { '<p>Ingen.</p>' }
    $html = @"
