function Invoke-NetIPApplyConfiguration {
    [CmdletBinding()]
    param()

    if (-not $sync.State.Plan) {
        [System.Windows.MessageBox]::Show('Generér en plan før du udfører ændringer.', $sync.App.Name, 'OK', 'Warning') | Out-Null
        return
    }
    $config = Get-NetIPConfigFromUI
    $plan = $sync.State.Plan
    $summary = @"
Følgende udføres:

Brugere:
- $($plan.Account1UPN): $($plan.Account1Status)
- $($plan.Account2UPN): $($plan.Account2Status)

Eksisterende passwords ændres ikke.
Gruppe: $($plan.GroupName) / $($plan.GroupStatus)
Medlemskab opdateres: $($plan.AddAccountsToGroup)
Global Administrator tildeles direkte til begge konti: Ja
Conditional Access policies patches: $($plan.PatchConditionalAccess)
Antal policies der patches: $(@($plan.CAPoliciesToChange).Count)

CA policies bliver backuppet før patching.
Genererede passwords vises én gang og gemmes ikke.

Vil du fortsætte?
"@
    $answer = [System.Windows.MessageBox]::Show($summary, $sync.App.Name, 'YesNo', 'Warning')
    if ($answer -ne 'Yes') { return }

    Invoke-NetIPRunspace -ArgumentList @($config) -ScriptBlock {
        param($config)
        Write-NetIPStatus -Busy -Message 'Anvender konfiguration...'
        $tenant = Get-NetIPTenantInfo
        $output = if ($sync.State.OutputFolder) { $sync.State.OutputFolder } else { New-NetIPOutputFolder -TenantId $tenant.TenantId }
        New-Item -ItemType Directory -Force -Path $output | Out-Null

        $upn1 = ConvertTo-BreakGlassUpn -Prefix $config.UserPrefix1 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
        $upn2 = ConvertTo-BreakGlassUpn -Prefix $config.UserPrefix2 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
        $group = Ensure-NetIPSecurityGroup -DisplayName $config.GroupName -Description $config.GroupDescription -CreateIfMissing ([bool]$config.CreateGroup) -Apply $true
        Write-NetIPLog -Level PASS -Message "Gruppe håndteret: $($config.GroupName)"

        $createdPasswords = @()
        $users = [System.Collections.Generic.List[object]]::new()
        foreach ($item in @(
            @{ DisplayName = $config.DisplayName1; Upn = $upn1 },
            @{ DisplayName = $config.DisplayName2; Upn = $upn2 }
        )) {
            $existing = Get-NetIPUserByUpn -UserPrincipalName $item.Upn
            if ($existing) {
                $existing | Add-Member -MemberType NoteProperty -Name EnsureStatus -Value 'AlreadyExists' -Force
                $users.Add($existing)
                Write-NetIPLog -Level PASS -Message "Bruger findes og genbruges: $($item.Upn)"
                continue
            }
            if (-not $config.CreateUsers) {
                $users.Add([pscustomobject]@{ id=''; displayName=$item.DisplayName; userPrincipalName=$item.Upn; EnsureStatus='SkippedMissing' })
                Write-NetIPLog -Level WARN -Message "Bruger mangler og oprettes ikke: $($item.Upn)"
                continue
            }
            $password = New-NetIPRandomPassword
            $user = New-BreakGlassUser -DisplayName $item.DisplayName -UserPrincipalName $item.Upn -Password $password
            $users.Add($user)
            $createdPasswords += [pscustomobject]@{ UserPrincipalName = $item.Upn; Password = $password }
            Write-NetIPLog -Level PASS -Message "Bruger oprettet: $($item.Upn)"
        }

        $membership = @()
        if ($config.AddUsersToGroup) {
            foreach ($user in $users | Where-Object { Get-NetIPObjectPropertyValue -InputObject $_ -Name 'id' }) {
                $membership += Ensure-NetIPGroupMember -Group $group -User $user -Apply $true
            }
        }
        else {
            $membership += [pscustomobject]@{ Status='Skipped'; Detail='Gruppemedlemskab er fravalgt.' }
        }

        $roleDefinition = Get-NetIPGlobalAdministratorRoleDefinition
        $roleAssignments = @()
        foreach ($user in $users | Where-Object { Get-NetIPObjectPropertyValue -InputObject $_ -Name 'id' }) {
            $roleAssignments += Ensure-NetIPGlobalAdministratorAssignment -User $user -RoleDefinition $roleDefinition -Apply $true
        }

        $policies = @(Get-NetIPConditionalAccessPolicies)
        $backupPath = ''
        $caResults = @()
        $alreadyExcluded = @()
        $groupId = [string](Get-NetIPObjectPropertyValue -InputObject $group -Name 'id')
        $groupDisplayName = [string](Get-NetIPObjectPropertyValue -InputObject $group -Name 'displayName')
        $groupStatus = [string](Get-NetIPObjectPropertyValue -InputObject $group -Name 'EnsureStatus')
        if ($group -and $groupId) {
            foreach ($policy in $policies) {
                $excludeGroups = @(Get-NetIPObjectPropertyValue -InputObject (Get-NetIPObjectPropertyValue -InputObject (Get-NetIPObjectPropertyValue -InputObject $policy -Name 'conditions') -Name 'users') -Name 'excludeGroups')
                if ($excludeGroups -contains $groupId) {
                    $alreadyExcluded += [pscustomobject]@{
                        Policy = [string](Get-NetIPObjectPropertyValue -InputObject $policy -Name 'displayName')
                        PolicyId = [string](Get-NetIPObjectPropertyValue -InputObject $policy -Name 'id')
                        Status = 'AlreadyExcluded'
                    }
                }
            }
        }
        if ($config.PatchCAPolicies -and $group -and $groupId) {
            $backupPath = Backup-NetIPConditionalAccessPolicies -Policies $policies -OutputFolder $output
            $caResults = Add-NetIPGroupExclusionToCAPolicies -Policies $policies -GroupId $groupId -Apply $true
        }

        $changed = @($caResults | Where-Object Status -eq 'Patched')
        $failed = @($caResults | Where-Object Status -eq 'Failed')
        $account1Status = [string](Get-NetIPObjectPropertyValue -InputObject $users[0] -Name 'EnsureStatus')
        $account2Status = [string](Get-NetIPObjectPropertyValue -InputObject $users[1] -Name 'EnsureStatus')
        $result = [pscustomobject]@{
            TenantDisplayName = $tenant.TenantDisplayName
            TenantId = $tenant.TenantId
            Timestamp = (Get-Date).ToString('o')
            Operator = $sync.State.GraphAccount
            OnMicrosoftDomain = $tenant.OnMicrosoftDomain
            Account1 = [pscustomobject]@{ DisplayName=$config.DisplayName1; UserPrincipalName=$upn1; Status=$account1Status }
            Account2 = [pscustomobject]@{ DisplayName=$config.DisplayName2; UserPrincipalName=$upn2; Status=$account2Status }
            Group = [pscustomobject]@{ DisplayName=$groupDisplayName; Id=$groupId; Status=$groupStatus }
            GroupMembership = $membership
            RoleAssignments = $roleAssignments
            CAExclusionsEnabled = [bool]$config.PatchCAPolicies
            CAPoliciesChangedCount = $changed.Count
            CAPoliciesChanged = $changed
            CAPoliciesAlreadyExcluded = $alreadyExcluded
            CAPoliciesFailed = $failed
            CABackupPath = $backupPath
            Warnings = @($sync.State.Warnings)
        }
        $sync.State.Result = $result
        Save-NetIPResultJson -Result $result -OutputFolder $output | Out-Null
        $handoff = New-NetIPHandoffHtml -Result $result -OutputFolder $output
        $sync.State.HandoffPath = $handoff
        if ($createdPasswords.Count -gt 0) {
            $sync.State.CreatedPasswords = $createdPasswords
            Show-NetIPCreatedPasswordsOnce -CreatedPasswords $createdPasswords
        }
        $sync.Form.Dispatcher.Invoke([System.Action]{
            $sync.WPFOutputFolder.Text = $sync.State.OutputFolder
            $sync.WPFHandoffPath.Text = $sync.State.HandoffPath
            Invoke-NetIPWPFButton -Name 'WPFStepHandoff'
        })
        Write-NetIPStatus -Message 'Konfiguration er anvendt, og handoff er genereret.'
    }
}

function Invoke-NetIPBuildPlan {
    [CmdletBinding()]
    param()

    if (-not $sync.State.GraphConnected -and -not $sync.App.Mock) {
        [System.Windows.MessageBox]::Show('Du skal først forbinde til Microsoft Graph.', $sync.App.Name, 'OK', 'Warning') | Out-Null
        return
    }
    $config = Get-NetIPConfigFromUI
    Invoke-NetIPRunspace -ArgumentList @($config) -ScriptBlock {
        param($config)
        Write-NetIPStatus -Busy -Message 'Genererer plan...'
        $plan = New-NetIPPlanObject -Config $config -Discovery $sync.State.Discovery
        if (-not $sync.State.OutputFolder) {
            $sync.State.OutputFolder = New-NetIPOutputFolder -TenantId $plan.TenantId
        }
        $plan.OutputFolder = $sync.State.OutputFolder
        $plan.HandoffPath = Join-Path $sync.State.OutputFolder 'handoff.html'
        Export-NetIPJsonSafe -InputObject $plan -Path (Join-Path $sync.State.OutputFolder 'plan.json') -Depth 30 | Out-Null
        $text = @"
Tenant: $($plan.TenantDisplayName) / $($plan.TenantId)
Domain: $($plan.OnMicrosoftDomain)

Konto 1: $($plan.Account1DisplayName) / $($plan.Account1UPN) / $($plan.Account1Status)
Konto 2: $($plan.Account2DisplayName) / $($plan.Account2UPN) / $($plan.Account2Status)

Gruppe: $($plan.GroupName) / $($plan.GroupStatus)
Tilføj konti til gruppe: $($plan.AddAccountsToGroup)
Tildel Global Administrator: $($plan.AssignGlobalAdministrator) / scope $($plan.RoleAssignmentScope)

Conditional Access policies fundet: $($plan.ConditionalAccessCount)
Patch CA policies: $($plan.PatchConditionalAccess)
Policies der ændres: $(@($plan.CAPoliciesToChange).Count)
Policies der allerede ekskluderer gruppen: $(@($plan.CAPoliciesAlreadyExcluded).Count)

Output folder: $($plan.OutputFolder)
Handoff: $($plan.HandoffPath)

Advarsler:
$($plan.Warnings -join [Environment]::NewLine)

JSON:
$($plan | ConvertTo-Json -Depth 30)
"@
        $sync.Form.Dispatcher.Invoke([System.Action]{
            $sync.WPFPlanText.Text = $text
            Invoke-NetIPWPFButton -Name 'WPFStepPlan'
        })
        Write-NetIPStatus -Message 'Plan er genereret.'
    }
}

function Invoke-NetIPConnectTenant {
    [CmdletBinding()]
    param()

    Invoke-NetIPRunspace -ScriptBlock {
        if ($sync.App.Mock) {
            $sync.State.GraphConnected = $true
            $sync.State.GraphAccount = 'mock.consultant@contoso.onmicrosoft.com'
            Get-NetIPTenantInfo | Out-Null
            Write-NetIPStatus -Message 'Mock tenant er forbundet.'
            return
        }

        Write-NetIPStatus -Busy -Message 'Forbinder til Microsoft Graph...'
        $module = Get-Module -ListAvailable -Name Microsoft.Graph.Authentication | Select-Object -First 1
        if (-not $module) {
            $install = $sync.Form.Dispatcher.Invoke([func[object]]{
                [System.Windows.MessageBox]::Show('Microsoft.Graph.Authentication mangler. Vil du installere modulet for CurrentUser fra PSGallery?', $sync.App.Name, 'YesNo', 'Question')
            })
            if ($install -ne 'Yes') {
                throw 'Microsoft Graph modulet mangler, og installation blev ikke godkendt.'
            }
            Install-Module -Name Microsoft.Graph.Authentication -Scope CurrentUser -Repository PSGallery -Force -AllowClobber -ErrorAction Stop
        }
        Import-Module Microsoft.Graph.Authentication -ErrorAction Stop
        $scopes = @($sync.configs.graphScopes)
        Connect-MgGraph -Scopes $scopes -ContextScope Process -NoWelcome -ErrorAction Stop | Out-Null
        $context = Get-MgContext
        $sync.State.GraphConnected = $true
        $sync.State.GraphAccount = [string]$context.Account
        $sync.State.GraphScopes = @($context.Scopes)
        Get-NetIPTenantInfo | Out-Null
        Write-NetIPStatus -Message 'Microsoft Graph er forbundet.'
    }
}

function Invoke-NetIPDiscovery {
    [CmdletBinding()]
    param()

    if (-not $sync.State.GraphConnected -and -not $sync.App.Mock) {
        [System.Windows.MessageBox]::Show("Du skal først forbinde til Microsoft Graph under trinnet 'Forbind'.", $sync.App.Name, 'OK', 'Warning') | Out-Null
        return
    }
    $config = Get-NetIPConfigFromUI
    Invoke-NetIPRunspace -ArgumentList @($config) -ScriptBlock {
        param($config)
        Write-NetIPStatus -Busy -Message 'Kører discovery...'
        $tenant = Get-NetIPTenantInfo
        $upn1 = ConvertTo-BreakGlassUpn -Prefix $config.UserPrefix1 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
        $upn2 = ConvertTo-BreakGlassUpn -Prefix $config.UserPrefix2 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
        $user1 = Get-NetIPUserByUpn -UserPrincipalName $upn1
        $user2 = Get-NetIPUserByUpn -UserPrincipalName $upn2
        $group = Get-NetIPGroupByDisplayName -DisplayName $config.GroupName
        $policies = @(Get-NetIPConditionalAccessPolicies)
        $already = @()
        $groupId = [string](Get-NetIPObjectPropertyValue -InputObject $group -Name 'id')
        if ($group -and $groupId) {
            foreach ($policy in $policies) {
                $excludeGroups = @(Get-NetIPObjectPropertyValue -InputObject (Get-NetIPObjectPropertyValue -InputObject (Get-NetIPObjectPropertyValue -InputObject $policy -Name 'conditions') -Name 'users') -Name 'excludeGroups')
                if ($excludeGroups -contains $groupId) { $already += $policy }
            }
        }
        $discovery = [pscustomobject]@{
            Tenant = $tenant
            User1 = $user1
            User2 = $user2
            Group = $group
            CAPolicies = $policies
            CAPoliciesAlreadyExcluded = $already
            TargetUPN1 = $upn1
            TargetUPN2 = $upn2
            Timestamp = (Get-Date).ToString('o')
        }
        $sync.State.Discovery = $discovery
        $summary = "User1: $(if($user1){'findes'}else{'mangler'}); User2: $(if($user2){'findes'}else{'mangler'}); Gruppe: $(if($group){'findes'}else{'mangler'}); CA policies: $($policies.Count)"
        $userMissingSeverity = if ($config.CreateUsers) { 'Warning' } else { 'Bad' }
        $groupMissingSeverity = if ($config.CreateGroup) { 'Warning' } else { 'Bad' }
        $excludedSeverity = if ($policies.Count -eq 0) {
            'Good'
        }
        elseif ($already.Count -eq $policies.Count) {
            'Good'
        }
        elseif ($config.PatchCAPolicies) {
            'Warning'
        }
        else {
            'Bad'
        }
        $summarySeverity = if ((-not $user1 -and -not $config.CreateUsers) -or (-not $user2 -and -not $config.CreateUsers) -or (-not $group -and -not $config.CreateGroup) -or $excludedSeverity -eq 'Bad') {
            'Bad'
        }
        elseif (-not $user1 -or -not $user2 -or -not $group -or $excludedSeverity -eq 'Warning') {
            'Warning'
        }
        else {
            'Good'
        }
        $lines = @(
            [pscustomobject]@{ Severity = 'Info'; Text = "Tenant: $($tenant.TenantDisplayName) / $($tenant.TenantId)" },
            [pscustomobject]@{ Severity = 'Info'; Text = "Domain: $($tenant.OnMicrosoftDomain)" },
            [pscustomobject]@{ Severity = if($user1){'Good'}else{$userMissingSeverity}; Text = "Target user 1: $upn1 - $(if($user1){'Findes'}elseif($config.CreateUsers){'Mangler - planlagt oprettet'}else{'Mangler - oprettelse er fravalgt'})" },
            [pscustomobject]@{ Severity = if($user2){'Good'}else{$userMissingSeverity}; Text = "Target user 2: $upn2 - $(if($user2){'Findes'}elseif($config.CreateUsers){'Mangler - planlagt oprettet'}else{'Mangler - oprettelse er fravalgt'})" },
            [pscustomobject]@{ Severity = if($group){'Good'}else{$groupMissingSeverity}; Text = "Group $($config.GroupName): $(if($group){'Findes'}elseif($config.CreateGroup){'Mangler - planlagt oprettet'}else{'Mangler - oprettelse er fravalgt'})" },
            [pscustomobject]@{ Severity = 'Info'; Text = "Conditional Access policies: $($policies.Count)" },
            [pscustomobject]@{ Severity = $excludedSeverity; Text = "Policies der allerede ekskluderer gruppen: $($already.Count) af $($policies.Count)" }
        )
        $sync.Form.Dispatcher.Invoke([System.Action]{
            $sync.WPFDiscoverySummary.Text = $summary
            $sync.WPFDiscoverySummary.Foreground = switch ($summarySeverity) {
                'Good' { [System.Windows.Media.Brushes]::ForestGreen }
                'Warning' { [System.Windows.Media.Brushes]::DarkOrange }
                'Bad' { [System.Windows.Media.Brushes]::Firebrick }
                default { [System.Windows.Media.Brushes]::Black }
            }
            $document = New-Object System.Windows.Documents.FlowDocument
            foreach ($line in $lines) {
                $paragraph = New-Object System.Windows.Documents.Paragraph
                $prefix = switch ($line.Severity) {
                    'Good' { '[OK] ' }
                    'Warning' { '[ADVARSEL] ' }
                    'Bad' { '[FEJL] ' }
                    default { '[INFO] ' }
                }
                $run = New-Object System.Windows.Documents.Run ($prefix + $line.Text)
                $run.Foreground = switch ($line.Severity) {
                    'Good' { [System.Windows.Media.Brushes]::ForestGreen }
                    'Warning' { [System.Windows.Media.Brushes]::DarkOrange }
                    'Bad' { [System.Windows.Media.Brushes]::Firebrick }
                    default { [System.Windows.Media.Brushes]::SlateGray }
                }
                $run.FontWeight = if ($line.Severity -eq 'Info') { [System.Windows.FontWeights]::Normal } else { [System.Windows.FontWeights]::SemiBold }
                [void]$paragraph.Inlines.Add($run)
                [void]$document.Blocks.Add($paragraph)
            }
            $sync.WPFDiscoveryList.Document = $document
            Invoke-NetIPWPFButton -Name 'WPFStepDiscovery'
        })
        Write-NetIPStatus -Message 'Discovery er færdig.'
    }
}

