            <Setter Property="Margin" Value="0,0,0,8"/>
            <Setter Property="Padding" Value="12,6"/>
        </Style>
        <Style TargetType="TextBox">
            <Setter Property="MinHeight" Value="28"/>
            <Setter Property="Margin" Value="0,2,0,8"/>
        </Style>
        <Style TargetType="CheckBox">
            <Setter Property="Margin" Value="0,4,0,8"/>
        </Style>
        <Style TargetType="TextBlock">
            <Setter Property="TextWrapping" Value="Wrap"/>
        </Style>
    </Window.Resources>
    <Grid>
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
            <RowDefinition Height="Auto"/>
        </Grid.RowDefinitions>

        <Border Grid.Row="0" Background="#111827" Padding="18,14">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="Auto"/>
                </Grid.ColumnDefinitions>
                <StackPanel>
                    <TextBlock x:Name="WPFAppTitle" Text="Entra Break Glass Configurator" Foreground="White" FontSize="24" FontWeight="SemiBold"/>
                    <TextBlock x:Name="WPFAppSubtitle" Text="Simpel Microsoft Graph-baseret opsætning af break-glass konti og CA-exclude gruppe." Foreground="#CBD5E1" Margin="0,4,0,0"/>
                </StackPanel>
                <Border Grid.Column="1" BorderBrush="#64748B" BorderThickness="1" Background="#1F2937" CornerRadius="4" Padding="10,5" VerticalAlignment="Top">
                    <TextBlock x:Name="WPFVersionBadge" Foreground="#E5E7EB" FontWeight="SemiBold"/>
                </Border>
            </Grid>
        </Border>

        <Grid Grid.Row="1">
            <Grid.ColumnDefinitions>
                <ColumnDefinition Width="230"/>
                <ColumnDefinition Width="*"/>
            </Grid.ColumnDefinitions>
            <Border Grid.Column="0" Background="#E5E7EB" BorderBrush="#CBD5E1" BorderThickness="0,0,1,0" Padding="14">
                <StackPanel>
                    <Button x:Name="WPFStepWelcome" Content="1. Velkommen"/>
                    <Button x:Name="WPFStepConnect" Content="2. Forbind" IsEnabled="False"/>
                    <Button x:Name="WPFStepDiscovery" Content="3. Discovery" IsEnabled="False"/>
                    <Button x:Name="WPFStepConfig" Content="4. Konfiguration" IsEnabled="False"/>
                    <Button x:Name="WPFStepPlan" Content="5. Plan" IsEnabled="False"/>
                    <Button x:Name="WPFStepApply" Content="6. Udfør" IsEnabled="False"/>
                    <Button x:Name="WPFStepHandoff" Content="7. Handoff" IsEnabled="False"/>
                </StackPanel>
            </Border>

            <Grid Grid.Column="1" Margin="18">
                <Grid x:Name="WPFPageWelcome">
                    <ScrollViewer VerticalScrollBarVisibility="Auto">
                        <StackPanel MaxWidth="900">
                            <StackPanel Orientation="Horizontal" HorizontalAlignment="Right" Margin="0,0,0,12">
                                <TextBlock x:Name="WPFLanguageLabel" Text="Sprog" VerticalAlignment="Center" Margin="0,0,8,0"/>
                                <ComboBox x:Name="WPFLanguageSelector" Width="150" SelectedIndex="0">
                                    <ComboBoxItem Content="Dansk" Tag="da-DK"/>
                                    <ComboBoxItem Content="English" Tag="en-US"/>
                                </ComboBox>
                            </StackPanel>
                            <TextBlock Text="Velkommen" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <TextBlock Text="Dette værktøj opretter to break-glass konti på tenantens .onmicrosoft.com domæne, opretter gruppen CA-BreakGlass-Exclude og kan valgfrit ekskludere gruppen fra eksisterende Conditional Access-politikker."/>
                            <TextBlock Margin="0,12,0,0" Text="Værktøjet forbinder kun til Microsoft Graph. Det bruger ikke Azure, PIM, RMAU, FIDO2, Log Analytics eller Sentinel."/>
                            <TextBlock Margin="0,12,0,0" Text="Discovery og Plan foretager ingen ændringer. Ændringer udføres først i trinnet Udfør."/>
                            <TextBlock Margin="0,12,0,0" Text="Midlertidige adgangskoder vises kun én gang og gemmes ikke i log, JSON eller handoff dokument."/>
                            <CheckBox x:Name="WPFWelcomeRiskAccepted" Margin="0,24,0,0" Content="Jeg forstår at dette script ændrer sikkerhedskritisk tenant-konfiguration."/>
                        </StackPanel>
                    </ScrollViewer>
                </Grid>

                <Grid x:Name="WPFPageConnect" Visibility="Collapsed">
                    <ScrollViewer VerticalScrollBarVisibility="Auto">
                        <StackPanel MaxWidth="900">
                            <TextBlock Text="Forbind" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <TextBlock Text="Forbind én gang til Microsoft Graph. Samme session bruges til discovery, plan og udførsel."/>
                            <TextBlock Text="Requested Graph scopes:" FontWeight="SemiBold" Margin="0,16,0,4"/>
                            <TextBox x:Name="WPFGraphScopes" IsReadOnly="True" AcceptsReturn="True" Height="100" FontFamily="Consolas"/>
                            <Button x:Name="WPFConnectTenant" Content="Forbind til Microsoft 365 tenant" Width="240" HorizontalAlignment="Left"/>
                            <UniformGrid Columns="2" Margin="0,14,0,0">
                                <TextBlock Text="Forbundet:" FontWeight="SemiBold"/>
                                <TextBlock x:Name="WPFGraphStatus" Text="Nej"/>
                                <TextBlock Text="Konto:" FontWeight="SemiBold"/>
                                <TextBlock x:Name="WPFGraphAccount"/>
                                <TextBlock Text="Tenant ID:" FontWeight="SemiBold"/>
                                <TextBlock x:Name="WPFTenantId"/>
                                <TextBlock Text="Tenant navn:" FontWeight="SemiBold"/>
                                <TextBlock x:Name="WPFTenantName"/>
                                <TextBlock Text=".onmicrosoft.com domæne:" FontWeight="SemiBold"/>
                                <TextBlock x:Name="WPFOnMicrosoftDomain"/>
                            </UniformGrid>
                        </StackPanel>
                    </ScrollViewer>
                </Grid>

                <Grid x:Name="WPFPageDiscovery" Visibility="Collapsed">
                    <DockPanel>
                        <StackPanel DockPanel.Dock="Top">
                            <TextBlock Text="Discovery" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <TextBlock Text="Discovery er read-only og kontrollerer kun de eksakte target UPNs, CA-BreakGlass-Exclude og eksisterende Conditional Access-politikker."/>
                            <Button x:Name="WPFRunDiscovery" Content="Kør discovery" Width="150" HorizontalAlignment="Left" Margin="0,14,0,8"/>
                            <TextBlock x:Name="WPFDiscoverySummary" FontWeight="SemiBold"/>
                        </StackPanel>
                        <RichTextBox x:Name="WPFDiscoveryList" IsReadOnly="True" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" FontFamily="Consolas" BorderBrush="#CBD5E1" BorderThickness="1" Background="White"/>
                    </DockPanel>
                </Grid>

                <Grid x:Name="WPFPageConfig" Visibility="Collapsed">
                    <ScrollViewer VerticalScrollBarVisibility="Auto">
                        <Grid MaxWidth="920">
                            <Grid.ColumnDefinitions>
                                <ColumnDefinition Width="220"/>
                                <ColumnDefinition Width="*"/>
                                <ColumnDefinition Width="220"/>
                                <ColumnDefinition Width="*"/>
                            </Grid.ColumnDefinitions>
                            <Grid.RowDefinitions>
                                <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
                                <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
                                <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
                                <RowDefinition Height="Auto"/><RowDefinition Height="Auto"/>
                            </Grid.RowDefinitions>
                            <TextBlock Grid.Row="0" Grid.ColumnSpan="4" Text="Konfiguration" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <TextBlock Grid.Row="1" Grid.Column="0" Text="Account 1 display name"/>
                            <TextBox x:Name="WPFDisplayName1" Grid.Row="1" Grid.Column="1" Margin="0,2,16,8"/>
                            <TextBlock Grid.Row="1" Grid.Column="2" Text="Account 1 UPN prefix"/>
                            <TextBox x:Name="WPFUserPrefix1" Grid.Row="1" Grid.Column="3"/>
                            <TextBlock Grid.Row="2" Grid.Column="0" Text="Account 2 display name"/>
                            <TextBox x:Name="WPFDisplayName2" Grid.Row="2" Grid.Column="1" Margin="0,2,16,8"/>
                            <TextBlock Grid.Row="2" Grid.Column="2" Text="Account 2 UPN prefix"/>
                            <TextBox x:Name="WPFUserPrefix2" Grid.Row="2" Grid.Column="3"/>
                            <TextBlock Grid.Row="3" Grid.Column="0" Text="Domain"/>
                            <TextBox x:Name="WPFDomain" Grid.Row="3" Grid.Column="1" Grid.ColumnSpan="3" IsReadOnly="True"/>
                            <TextBlock Grid.Row="4" Grid.Column="0" Text="Final UPN preview"/>
                            <StackPanel Grid.Row="4" Grid.Column="1" Grid.ColumnSpan="3">
                                <TextBlock x:Name="WPFUpnPreview1" FontFamily="Consolas"/>
                                <TextBlock x:Name="WPFUpnPreview2" FontFamily="Consolas"/>
                            </StackPanel>
                            <TextBlock Grid.Row="5" Grid.Column="0" Text="Security group name"/>
                            <TextBox x:Name="WPFGroupName" Grid.Row="5" Grid.Column="1" Grid.ColumnSpan="3" IsReadOnly="True"/>
                            <TextBlock Grid.Row="6" Grid.Column="0" Text="Security group description"/>
                            <TextBox x:Name="WPFGroupDescription" Grid.Row="6" Grid.Column="1" Grid.ColumnSpan="3" IsReadOnly="True" TextWrapping="Wrap" Height="58"/>
                            <StackPanel Grid.Row="7" Grid.Column="0" Grid.ColumnSpan="4" Margin="0,10,0,0">
                                <CheckBox x:Name="WPFCreateUsers" Content="Opret brugere hvis de ikke findes"/>
                                <CheckBox x:Name="WPFCreateGroup" Content="Opret gruppen CA-BreakGlass-Exclude hvis den ikke findes"/>
                                <CheckBox x:Name="WPFAddUsersToGroup" Content="Tilføj break-glass konti til CA-BreakGlass-Exclude"/>
                                <CheckBox x:Name="WPFPatchCAPolicies" Content="Ekskludér CA-BreakGlass-Exclude fra alle eksisterende Conditional Access-politikker"/>
                                <TextBlock Foreground="#92400E" Text="Dette ændrer eksisterende Conditional Access-politikker. Der oprettes backup før ændringerne udføres."/>
                            </StackPanel>
                        </Grid>
                    </ScrollViewer>
                </Grid>

                <Grid x:Name="WPFPagePlan" Visibility="Collapsed">
                    <DockPanel>
                        <StackPanel DockPanel.Dock="Top">
                            <TextBlock Text="Plan" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <Button x:Name="WPFBuildPlan" Content="Generér plan" Width="150" HorizontalAlignment="Left"/>
                        </StackPanel>
                        <TextBox x:Name="WPFPlanText" IsReadOnly="True" AcceptsReturn="True" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" FontFamily="Consolas"/>
                    </DockPanel>
                </Grid>

                <Grid x:Name="WPFPageApply" Visibility="Collapsed">
                    <DockPanel>
                        <StackPanel DockPanel.Dock="Top">
                            <TextBlock Text="Udfør" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                            <TextBlock Text="Dette er det eneste trin der ændrer tenant-konfiguration."/>
                            <Button x:Name="WPFApplyConfiguration" Content="Anvend konfiguration" Width="180" HorizontalAlignment="Left" Margin="0,14,0,8"/>
                        </StackPanel>
                        <TextBox x:Name="WPFExecutionLog" IsReadOnly="True" AcceptsReturn="True" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" FontFamily="Consolas"/>
                    </DockPanel>
                </Grid>

                <Grid x:Name="WPFPageHandoff" Visibility="Collapsed">
                    <StackPanel MaxWidth="900">
                        <TextBlock Text="Handoff" FontSize="22" FontWeight="SemiBold" Margin="0,0,0,12"/>
                        <TextBlock Text="Handoff-dokumentet genereres efter udførsel. Det indeholder ikke passwords."/>
                        <TextBlock Text="Output folder" FontWeight="SemiBold" Margin="0,18,0,4"/>
                        <TextBox x:Name="WPFOutputFolder" IsReadOnly="True"/>
                        <TextBlock Text="Handoff dokument" FontWeight="SemiBold" Margin="0,10,0,4"/>
                        <TextBox x:Name="WPFHandoffPath" IsReadOnly="True"/>
                        <StackPanel Orientation="Horizontal" Margin="0,12,0,0">
                            <Button x:Name="WPFOpenOutputFolder" Content="Åbn outputmappe" Width="150" Margin="0,0,8,0"/>
                            <Button x:Name="WPFOpenHandoff" Content="Åbn handoff" Width="130"/>
                        </StackPanel>
                    </StackPanel>
                </Grid>
            </Grid>
        </Grid>

        <Border Grid.Row="2" Background="#F1F5F9" BorderBrush="#CBD5E1" BorderThickness="0,1,0,0" Padding="12,8">
            <Grid>
                <Grid.ColumnDefinitions>
                    <ColumnDefinition Width="*"/>
                    <ColumnDefinition Width="220"/>
                </Grid.ColumnDefinitions>
                <TextBlock x:Name="WPFStatusText" Text="Klar"/>
                <ProgressBar x:Name="WPFProgressBar" Grid.Column="1" Height="14" IsIndeterminate="False"/>
            </Grid>
        </Border>
    </Grid>
</Window>

'@
$maxThreads = 1
$initialSessionState = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()
$initialSessionState.Variables.Add((New-Object System.Management.Automation.Runspaces.SessionStateVariableEntry -ArgumentList 'sync', $sync, $null))
$initialSessionState.Variables.Add((New-Object System.Management.Automation.Runspaces.SessionStateVariableEntry -ArgumentList 'DebugPreference', $DebugPreference, $null))

Get-ChildItem function:\ | Where-Object { $_.Name -like '*-NetIP*' -or $_.Name -like '*-BreakGlass*' } | ForEach-Object {
    $definition = Get-Content function:\$($_.Name)
    $initialSessionState.Commands.Add((New-Object System.Management.Automation.Runspaces.SessionStateFunctionEntry -ArgumentList $_.Name, $definition))
}

$sync.Runspace = [runspacefactory]::CreateRunspacePool(1, $maxThreads, $initialSessionState, $Host)
$sync.Runspace.ApartmentState = 'STA'
$sync.Runspace.ThreadOptions = 'ReuseThread'
$sync.Runspace.Open()

$inputXML = $inputXML -replace 'mc:Ignorable="d"', '' -replace 'x:Name', 'Name'
[xml]$xaml = $inputXML
$reader = New-Object System.Xml.XmlNodeReader $xaml
$sync.Form = [Windows.Markup.XamlReader]::Load($reader)

$xaml.SelectNodes("//*[@Name]") | ForEach-Object {
    $sync[$_.Name] = $sync.Form.FindName($_.Name)
}

Initialize-NetIPWPFUI

$sync.Keys | ForEach-Object {
    $control = $sync[$_]
    if ($control -and $control.GetType().Name -eq 'Button' -and $_ -like 'WPF*') {
        $control.Add_Click({
            param($sender, $eventArgs)
            Invoke-NetIPWPFButton -Name $sender.Name
        })
    }
}

foreach ($box in @('WPFDisplayName1','WPFUserPrefix1','WPFDisplayName2','WPFUserPrefix2')) {
    if ($sync[$box]) {
        $sync[$box].Add_TextChanged({ Update-NetIPUIState })
    }
}

$sync.WPFWelcomeRiskAccepted.Add_Checked({ Update-NetIPUIState })
$sync.WPFWelcomeRiskAccepted.Add_Unchecked({ Update-NetIPUIState })
if ($sync.WPFLanguageSelector) {
    $sync.WPFLanguageSelector.Add_SelectionChanged({
        $selected = $sync.WPFLanguageSelector.SelectedItem
        $language = if ($selected -and $selected.Tag) { [string]$selected.Tag } else { 'da-DK' }
        Set-NetIPLanguage -Language $language
        Update-NetIPUIState
    })
}

$sync.Form.Add_Closing({
    if ($sync.Runspace) {
        $sync.Runspace.Close()
        $sync.Runspace.Dispose()
    }
})

$sync.Form.ShowDialog() | Out-Null

